// Traduce titulo_es/texto_es a en/fr/de con DeepL y guarda en NocoDB.
// Anti-bucle: solo actua si md5(titulo_es+texto_es) difiere de es_hash.
// Respeta idiomas marcados en 'revisado' (ej: "en,fr").
const URL = $env.NOCODB_URL;
const TOK = $env.NOCODB_TOKEN;
const BASE = $env.NOCODB_BASE || 'Yoga';
const DEEPL = $env.DEEPL_API_KEY;
if (!URL || !TOK || !DEEPL) throw new Error('Faltan NOCODB_URL/NOCODB_TOKEN/DEEPL_API_KEY en el entorno de n8n');
const H = { 'xc-token': TOK, 'Content-Type': 'application/json' };

// --- extraer la(s) fila(s) del payload del webhook de NocoDB (tolerante a formatos) ---
const body = $json.body || $json;
let rows = body?.data?.rows || body?.data?.records || (body?.data ? [body.data] : []) ;
if (!Array.isArray(rows)) rows = [rows];
rows = rows.filter(r => r && (r.titulo_es || r.texto_es));
if (!rows.length) return [{ json: { ok: true, motivo: 'sin filas con contenido es' } }];

// --- localizar la tabla Actividades por nombre ---
const bases = await this.helpers.httpRequest({ url: `${URL}/api/v2/meta/bases`, headers: H, json: true });
const b = bases.list.find(x => x.title === BASE);
if (!b) throw new Error(`base ${BASE} no encontrada`);
const tabs = await this.helpers.httpRequest({ url: `${URL}/api/v2/meta/bases/${b.id}/tables`, headers: H, json: true });
const tAct = tabs.list.find(x => x.title === 'Actividades');
if (!tAct) throw new Error('tabla Actividades no encontrada');

const LANGS = { en: 'EN-GB', fr: 'FR', de: 'DE' };
async function deepl(texto, target) {
  if (!texto) return '';
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api-free.deepl.com/v2/translate',
    headers: { 'Authorization': `DeepL-Auth-Key ${DEEPL}`, 'Content-Type': 'application/json' },
    body: { text: [texto], source_lang: 'ES', target_lang: target },
    json: true
  });
  return r.translations[0].text;
}

const resultados = [];
for (const row of rows) {
  const id = row.Id;
  const tit = (row.titulo_es || '').trim();
  const txt = (row.texto_es || '').trim();
  if (!id || (!tit && !txt)) continue;
  const fnv = (s) => { let h = 0x811c9dc5; for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = (h * 0x01000193) >>> 0; } return h.toString(16); };
  const hash = fnv(tit + '|' + txt);
  if (row.es_hash === hash) { resultados.push({ id, accion: 'sin cambios (hash)' }); continue; }
  const revisado = (row.revisado || '').toLowerCase();
  const parche = { Id: id, es_hash: hash };
  for (const [idioma, target] of Object.entries(LANGS)) {
    if (revisado.includes(idioma)) continue;  // traduccion humana: no pisar
    if (tit) parche[`titulo_${idioma}`] = await deepl.call(this, tit, target);
    if (txt) parche[`texto_${idioma}`] = await deepl.call(this, txt, target);
  }
  await this.helpers.httpRequest({ method: 'PATCH', url: `${URL}/api/v2/tables/${tAct.id}/records`, headers: H, body: [parche], json: true });
  resultados.push({ id, accion: 'traducida', idiomas: Object.keys(LANGS).filter(i => !revisado.includes(i)) });
}
return [{ json: { ok: true, resultados } }];
